const inp = $input.first().json;

function b64(str) { return Buffer.from(str, 'utf-8').toString('base64'); }
function pad(n)   { return String(n).padStart(2,'0'); }

const src  = inp.course_id        || 'unknown_src';
const tgt  = inp.target_course_id || 'unknown_tgt';
const sl   = inp.source_language  || 'fr';
const tl   = (inp.target_language || 'en-US').split('-')[0];
const dir  = `${sl}>${tl}`;
const now  = new Date();
const date = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const base = `07_runs/${src}/output`;

// 1. Final HTML
const htmlContent = inp.final_html || '';
const htmlPath    = `${base}/${tgt}_localized_${dir}.html`;
const htmlB64     = b64(htmlContent);

// 2. Decision log
const logObj = {
  meta: { course_id: src, target_course_id: tgt, direction: dir, date, score_total: inp.score_total || null },
  a4_swap_log:       inp.a4_swap_log   || [],
  a5_qa_report:      inp.a5_qa_report  || {},
  a6_issue_log:      inp.a6_issue_log  || [],
  structural_checks: inp.structural_checks || []
};
const logPath = `${base}/${tgt}_decision_log_${dir}.json`;
const logB64  = b64(JSON.stringify(logObj, null, 2));

// 3. TM patch CSV
const tmEntries = inp.domain_tm_patch || [];
let csvTM = 'source_term,target_term,direction,domain,category,context_note,do_not_translate,validated,first_seen_course,last_updated\n';
for (const e of tmEntries) {
  csvTM += [e.source_term||'', e.target_term||'', dir,
    e.domain||inp.detected_domain||'', e.category||'',
    (e.context_note||'').replace(/,/g,'；'),
    e.do_not_translate||false, 'false', src, date].join(',') + '\n';
}
const tmPath = `${base}/${tgt}_tm_patch_${dir}.csv`;
const tmB64  = b64(csvTM);

// 4. Phase 2 ToDo CSVs
const pending = inp.pending_phase2 || [];
const byType  = { static_graphic: [], oc_course_link: [], video: [], external_link: [] };
for (const item of pending) { if (byType[item.type]) byType[item.type].push(item); }

const csvHeader   = 'type,chapter_index,chunk_index,location,source_value,anchor_text,action_required\n';
const linksHeader = 'type,chapter_index,chunk_index,location,source_value,anchor_text,action_required,is_aws,file_extension\n';
function isAWS(u) { return /amazonaws\.com|s3\.aws|cloudfront\.net/i.test(u||''); }
function fileExt(u) { const m = (u||'').split('?')[0].match(/\.([a-z0-9]+)$/i); return m ? m[1].toLowerCase() : ''; }
function toRow(i) {
  return [i.type||'', i.chapter_index||0, i.chunk_index||0,
    (i.location||'').replace(/,/g,'；'), (i.source_value||'').replace(/,/g,'；'),
    (i.anchor_text||'').replace(/,/g,'；'), (i.action_required||'').replace(/,/g,'；')].join(',');
}
function toLinksRow(i) {
  const url = i.source_value||'';
  return [i.type||'', i.chapter_index||0, i.chunk_index||0,
    (i.location||'').replace(/,/g,'；'), url.replace(/,/g,'；'),
    (i.anchor_text||'').replace(/,/g,'；'), (i.action_required||'').replace(/,/g,'；'),
    isAWS(url), fileExt(url)].join(',');
}
const linksItems = [...byType.oc_course_link, ...byType.external_link];

const graphicsPath = `${base}/${tgt}_todo_static_graphics_${dir}.csv`;
const linksPath    = `${base}/${tgt}_todo_external_links_${dir}.csv`;
const videosPath   = `${base}/${tgt}_todo_videos_${dir}.csv`;
const graphicsB64  = b64(csvHeader + byType.static_graphic.map(toRow).join('\n'));
const linksB64     = b64(linksHeader + linksItems.map(toLinksRow).join('\n'));
const videosB64    = b64(csvHeader + byType.video.map(toRow).join('\n'));

const ghBase = `https://github.com/jeremieborrotzu-blip/Ressources_Loc_OSS/blob/main/`;

// 5a. Review MD — HTML mirror only (clean, for Notion import)
const reviewMd = `# ${tgt} — Localized Content Review

| Field | Value |
|---|---|
| Source ID | \`${src}\` |
| Target ID | \`${tgt}\` |
| Direction | ${dir} |
| Date | ${date} |
| QA Score | ${inp.score_total ? inp.score_total + '/100' : 'N/A'} |
| Structural integrity | ${inp.structural_integrity ? '✅ OK' : '❌ BLOCKED'} |

---

${htmlContent || '<!-- no HTML content -->'}
`;
const mdPath = `${base}/${tgt}_review_${dir}.md`;
const mdB64  = b64(reviewMd);

// 5b. QA Report MD — score + issues + Phase 2 ToDo (for PM)
function todoTable(items, cols) {
  if (!items.length) return '_None detected._\n';
  const h = '| ' + cols.join(' | ') + ' |';
  const s = '| ' + cols.map(() => '---').join(' | ') + ' |';
  const r = items.map(i => '| ' + cols.map(c => String(i[c]||'').replace(/\|/g,'\\|').slice(0,80)).join(' | ') + ' |');
  return [h, s, ...r].join('\n') + '\n';
}
const a6Issues = (inp.a6_issue_log || [])
  .map(i => `- **[${i.severity}]** \`${i.location||'unknown'}\`: ${i.issue}`).join('\n') || 'None.';

const qaMd = `# QA Report — ${tgt}

| Field | Value |
|---|---|
| Source ID | \`${src}\` |
| Target ID | \`${tgt}\` |
| Direction | ${dir} |
| Date | ${date} |
| QA Score | ${inp.score_total ? inp.score_total + '/100' : 'N/A'} |
| Structural integrity | ${inp.structural_integrity ? '✅ OK' : '❌ BLOCKED'} |

## A5 QA Summary

${inp.a5_summary || 'No QA summary available.'}

## A6 Issues

${a6Issues}

---

## Reste à faire — Phase 2

### 🖼 Static Graphics (pending A8)

${todoTable(byType.static_graphic, ['location','source_value','anchor_text','action_required'])}
→ [Full CSV](${ghBase}${graphicsPath})

### 🔗 External Links & OC Course Links

${todoTable(linksItems, ['type','location','source_value','anchor_text','action_required'])}
→ [Full CSV](${ghBase}${linksPath})

### 🎬 Videos (pending A7)

${todoTable(byType.video, ['location','source_value','action_required'])}
→ [Full CSV](${ghBase}${videosPath})

---

## GitHub Deliverables

- [Localized HTML](${ghBase}${htmlPath})
- [Review MD (Notion)](${ghBase}${mdPath})
- [Decision Log](${ghBase}${logPath})
- [TM Patch](${ghBase}${tmPath})
`;
const qaPath = `${base}/${tgt}_qa_report_${dir}.md`;
const qaB64  = b64(qaMd);

return [{ json: {
  htmlPath, htmlB64,
  logPath,  logB64,
  tmPath,   tmB64,
  mdPath,   mdB64,
  qaPath,   qaB64,
  graphicsPath, graphicsB64,
  linksPath,    linksB64,
  videosPath,   videosB64,
  repo: 'jeremieborrotzu-blip/Ressources_Loc_OSS',
  course_id: src, target_course_id: tgt,
  direction: dir, date,
  score_total: inp.score_total,
  structural_integrity: inp.structural_integrity,
  enabled_modules: inp.enabled_modules || [],
  pending_counts: {
    static_graphics: byType.static_graphic.length,
    oc_course_links: byType.oc_course_link.length,
    external_links:  byType.external_link.length,
    videos:          byType.video.length
  }
}}];

